import { GlideRecord } from '@servicenow/glide';
export function generateNumber(current, previous) {
    // Generate auto-number with prefix ELC followed by a padded sequence
    const gr = new GlideRecord('x_2177382_employee_lifecycle');
    gr.orderByDesc('sys_created_on');
    gr.setLimit(1);
    gr.query();
    let nextNumber = 1;
    if (gr.next()) {
        const lastNumber = gr.getValue('number');
        if (lastNumber) {
            const numPart = lastNumber.replace('ELC', '');
            const parsed = parseInt(numPart, 10);
            if (!isNaN(parsed)) {
                nextNumber = parsed + 1;
            }
        }
    }
    // Pad with zeros to 7 digits (e.g., ELC0000001)
    const paddedNumber = String(nextNumber).padStart(7, '0');
    current.setValue('number', 'ELC' + paddedNumber);
}
